import React, { useState, useEffect, useContext } from 'react';
import { useParams, Link } from 'react-router-dom';
import { CartContext } from '../context/CartContext';
import Header from '../components/common/Header';
import Navbar from '../components/common/Navbar';
import Footer from '../components/common/Footer';

const ProductDetail = () => {
  const { id } = useParams();
  const [product, setProduct] = useState(null);
  const [relatedProducts, setRelatedProducts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [quantity, setQuantity] = useState(1);
  const [selectedImage, setSelectedImage] = useState(0);
  const { addToCart } = useContext(CartContext);

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000';

  useEffect(() => {
    fetchProduct();
    fetchRelatedProducts();
  }, [id]);

  const fetchProduct = async () => {
    try {
      const response = await fetch(`${API_URL}/api/products/${id}`);
      if (response.ok) {
        const data = await response.json();
        setProduct(data);
      } else {
        setError('Không tìm thấy sản phẩm');
      }
    } catch (error) {
      setError('Lỗi kết nối đến server');
    } finally {
      setLoading(false);
    }
  };

  const fetchRelatedProducts = async () => {
    try {
      const response = await fetch(`${API_URL}/api/products/${id}/related`);
      if (response.ok) {
        const data = await response.json();
        setRelatedProducts(data);
      }
    } catch (error) {
      console.error('Error fetching related products:', error);
    }
  };

  const handleAddToCart = () => {
    if (!product) return;
    const cartItem = {
      _id: product._id,
      name: product.name,
      price: product.price,
      discountPrice: product.discountPrice,
      images: product.images,
      image: product.images?.[0],
      quantity,
    };
    addToCart(cartItem);
    alert(`Đã thêm ${quantity} ${product.name} vào giỏ hàng!`);
  };

  if (loading) {
    return (
      <div className="flex flex-col min-h-screen">
        <Header />
        <Navbar />
        <main className="flex-1 flex items-center justify-center">
          <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-green-700"></div>
        </main>
        <Footer />
      </div>
    );
  }

  if (error || !product) {
    return (
      <div className="flex flex-col min-h-screen">
        <Header />
        <Navbar />
        <main className="flex-1 flex items-center justify-center">
          <div className="text-center">
            <h2 className="text-2xl font-bold text-gray-800 mb-4">
              {error || 'Không tìm thấy sản phẩm'}
            </h2>
            <Link to="/product" className="text-green-700 hover:underline">
              ← Quay về danh sách sản phẩm
            </Link>
          </div>
        </main>
        <Footer />
      </div>
    );
  }

  const displayPrice = product.discountPrice ?? product.price ?? 0;
  const hasDiscount = product.discountPrice && product.discountPrice < product.price;

  const normalize = (path) => {
    if (!path) return '/placeholder.png';
    const fixed = path.replace(/\\/g, '/');
    return fixed.startsWith('http') ? fixed : `${API_URL}${fixed}`;
  };

  return (
    <div className="flex flex-col min-h-screen">
      <Header />
      <Navbar />
      <main className="flex-1 p-4 max-w-6xl mx-auto">
        {/* Product Detail */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-8 mb-12">
          {/* Ảnh chính */}
          <div className="space-y-4">
            <div className="aspect-square bg-gray-100 rounded-lg overflow-hidden">
              <img
                src={normalize(product.images?.[selectedImage])}
                alt={product.name}
                className="w-full h-full object-cover"
                onError={(e) => (e.currentTarget.src = '/placeholder.png')}
              />
            </div>

            {/* Thumbnail */}
            {product.images?.length > 1 && (
              <div className="flex gap-2 overflow-x-auto">
                {product.images.map((image, index) => (
                  <button
                    key={index}
                    onClick={() => setSelectedImage(index)}
                    className={`flex-shrink-0 w-16 h-16 rounded border-2 overflow-hidden ${
                      selectedImage === index ? 'border-green-700' : 'border-gray-200'
                    }`}
                  >
                    <img
                      src={normalize(image)}
                      alt={`${product.name} ${index + 1}`}
                      className="w-full h-full object-cover"
                      onError={(e) => (e.currentTarget.src = '/placeholder.png')}
                    />
                  </button>
                ))}
              </div>
            )}
          </div>

          {/* Thông tin */}
          <div className="space-y-6">
            <h1 className="text-3xl font-bold text-gray-800 mb-2">{product.name}</h1>

            <div className="mb-6">
              {hasDiscount ? (
                <div className="space-y-1">
                  <div className="text-3xl font-bold text-red-600">
                    {displayPrice.toLocaleString('vi-VN')}₫
                  </div>
                  <div className="text-lg text-gray-500 line-through">
                    {product.price.toLocaleString('vi-VN')}₫
                  </div>
                </div>
              ) : (
                <div className="text-3xl font-bold text-red-600">
                  {displayPrice.toLocaleString('vi-VN')}₫
                </div>
              )}
            </div>

            <p className="text-gray-600">{product.description || 'Hoa tặng sinh nhật'}</p>

            <div className="flex gap-4 mt-6">
              <button
                onClick={handleAddToCart}
                className="flex-1 bg-green-700 text-white py-3 px-6 rounded-lg hover:bg-green-600 transition-colors font-medium"
              >
                🛒 Thêm vào giỏ
              </button>
              <button className="px-6 py-3 border border-gray-300 rounded-lg hover:bg-gray-50 transition-colors">
                ❤️ Yêu thích
              </button>
            </div>
          </div>
        </div>

        {/* Sản phẩm liên quan */}
        {relatedProducts.length > 0 && (
          <div>
            <h2 className="text-2xl font-bold text-gray-800 mb-6">Sản phẩm liên quan</h2>
            <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-4 gap-6">
              {relatedProducts.map((rp) => (
                <Link
                  key={rp._id}
                  to={`/product/${rp._id}`}
                  className="bg-white rounded-lg shadow-md overflow-hidden hover:shadow-lg transition-shadow"
                >
                  <div className="aspect-square bg-gray-100">
                    <img
                      src={normalize(rp.images?.[0])}
                      alt={rp.name}
                      className="w-full h-full object-cover"
                      onError={(e) => (e.currentTarget.src = '/placeholder.png')}
                    />
                  </div>
                  <div className="p-4">
                    <h3 className="font-medium text-gray-800 mb-2 line-clamp-2">{rp.name}</h3>
                    <div className="text-red-600 font-bold">
                      {(rp.discountPrice || rp.price).toLocaleString('vi-VN')}₫
                    </div>
                    {rp.discountPrice && (
                      <div className="text-gray-500 text-sm line-through">
                        {rp.price.toLocaleString('vi-VN')}₫
                      </div>
                    )}
                  </div>
                </Link>
              ))}
            </div>
          </div>
        )}
      </main>
      <Footer />
    </div>
  );
};

export default ProductDetail;
